async def check_sub(uid):
    if not CHANNEL_ID: return True
    try:
        m = await bot.get_chat_member(CHANNEL_ID, uid)
        if m.status in ("left","kicked"): return False
    except: return True
    if CHAT_ID:
        try:
            m = await bot.get_chat_member(CHAT_ID, uid)
            if m.status in ("left","kicked"): return False
        except: pass
    return True

